BOOL deleteLinkFromStarupFolder(string linkName)
{
	CHAR szStartPath[MAX_PATH] = { 0 };
	SHGetSpecialFolderPathA(NULL, szStartPath, CSIDL_STARTUP, 0);
	string path = &szStartPath[0];
	path += "\\" + linkName;
	return DeleteFileA(path.c_str());
