# 文件相关处理,copy,move,delete

```c++
CopyFile(),DeleteFile(),MoveFile()


#define OP_RENAME		0
#define OP_COPY			1
#define OP_DELETE		2
#define OP_MOVE			3
/*
	rename file or directory
	@param iType [in] 0 rename, 1 copy,2 delete,3 move
	0 success
	not zero failed.
*/
int filePathProc(const wchar_t *pFrom, const wchar_t *pTo, int iType)
{
	SHFILEOPSTRUCT FileOp = { 0 };
	wchar_t src[MAX_PATH] = { '\0' };
	wchar_t dst[MAX_PATH] = { '\0' };
	if ( NULL == pTo )
	{
		FileOp.pTo = NULL;
	} else
	{
		_tcscpy(dst, pTo);
		FileOp.pTo = dst;
	}
	if ( NULL == pFrom )
	{
		return 1;
	}
	_tcscpy(src, pFrom);

	switch (iType)
	{
	case 0:
		FileOp.wFunc = FO_RENAME;
		break;
	case 1:
		FileOp.wFunc = FO_COPY;
		break;
	case 2:
		FileOp.wFunc = FO_DELETE;
		FileOp.pTo = NULL;
		break;
	case 3:
		FileOp.wFunc = FO_MOVE;
	default:
		break;
	}
	FileOp.fFlags = FOF_NOCONFIRMATION | FOF_ALLOWUNDO | FOF_NOCONFIRMMKDIR;   //不出现确认对话框 
	FileOp.pFrom = src;

	return SHFileOperation(&FileOp);
}

