int GetAppPath(std::string &sPath)
{
    char buf[4097] = { 0 };
    long size;
    char *ptr;
    size = pathconf(".", _PC_PATH_MAX);
    if ((ptr = new char(size)) != NULL)
    {
        memset(ptr, 0, size);
        sprintf(ptr, "/proc/%d/exe", getpid());
    } else return -1;
    readlink(ptr, buf, size);
    delete[] ptr;
    ptr = NULL;
    sPath = buf;
    int nPos = sPath.find_last_of("/");
    sPath = sPath.substr(0, nPos + 1);
    return 0;
}
