## 字符串插入
```js
//插入 参数说明：str表示原字符串变量，flg表示要插入的字符串，sn表示要插入的位置
function str_insert(src, insertStr, pos) {
    var newStr = "";
    for (var i = 0; i < src.length; i += pos) {
        var tmp = src.substring(i, i + pos);
        newStr += tmp + insertStr;
    }
    return newStr;
}
