```

3. 声明事件类
可以在这里面放需要传递的数据结构
```c
//使用SNotifyCenter的异步事件
class EventNotify : public TplEventArgs<EventNotify>
{
	SOUI_CLASS_NAME(EventNotify, L"on_event_notify")
public:
	EventNotify(SObject *pSender) :TplEventArgs<EventNotify>(pSender) {}
	enum { EventID = EVT_EXTERNAL_BEGIN + 30000 };

	int nData;
};
```

4. 在事件接收窗口加入相关信息

```
//异步事件相关
bool OnEventNotify(EventArgs *e);
//Event Sender ID
enum { SENDER_ID = 30000 };
virtual int GetID() const { return SENDER_ID; }

	//soui消息
EVENT_MAP_BEGIN()
	...
	//<--通知中心事件
	EVENT_ID_HANDLER(SENDER_ID, EventNotify::EventID, OnEventNotify)
	//-->
  ...
	EVENT_MAP_END()


bool FloatWin::OnEventNotify(EventArgs *e)
{
	EventNotify *pEvt = sobj_cast<EventNotify>(e);
	SStringW strMsg = SStringW().Format(L"event thread, sleep = %d", pEvt->nData);

	MessageBox(this->m_hWnd, L"OnEventNotify", L"ss", MB_OK);
	return false;
}
```

5. 在事件发送窗口头文件里添加
这里的事件ID应该需要和接收定义的一致。  

```
//Event Sender ID
	enum { SENDER_ID = 30000 };
	virtual int GetID() const { return SENDER_ID; }
```

6. 产生事件

```
void DlgNotify::OnBtnConfirm()
{
	EventNotify* pEvt = new EventNotify(this);
	// login ui
	pEvt->nData = 2;
	SNotifyCenter::getSingleton().FireEventAsync(pEvt);
	pEvt->Release();

	OnClose();
}
