int readJsonFromFile(wstring filePath, map<string,string>& out)
{
	int iRet = 0;
	Json::Reader reader;
	Json::Value root;

	//从文件中读取，保证当前文件有test.json文件
	ifstream in(filePath, ios::binary);
	if (!in.is_open())	
	{
		iRet = -1;
	}
	else
	{
		if (reader.parse(in, root))
		{
			map<string, string>::iterator  it;
			for ( it = out.begin(); it != out.end(); ++it)
			{
				out[ it->first ] = root[ it->first ].asString();
			}
		}
		else
		{
			iRet = -2;
		}
	}
	in.close();
	return 0;
}
