@Component
public class DateTimeConverter implements Converter<String, Date>
{

	@Override
	public Date convert(String source)
	{
		DateFormat df = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss");
		Date date = null;
		try
		{
			date = df.parse(source);
		} catch (ParseException e)
		{
			e.printStackTrace();
		}
		return date;
	}

}
